109→/// Messages driving the debugger state machine.
110→pub enum Msg {
111→    /// Load VM assembly and initialize the emulator.
112→    Init,
113→    /// Run a batch of instructions.
114→    Tick,
115→    /// Reset emulator to initial state.
116→    Reset,
117→    /// Step one p-code instruction (run COR24 until VM pc changes).
118→    StepPcode,
119→    /// Step one COR24 host instruction.
120→    StepHost,
121→    /// Toggle run/pause.
122→    PauseResume,
123→    /// Toggle COR24 drill-down panel visibility.
124→    ToggleHost,
125→}
126→
127→pub struct Debugger {
128→    emulator: EmulatorCore,
129→    config: VmConfig,
130→    output: String,
131→    running: bool,
132→    halted: bool,
133→    _tick_handle: Option<Timeout>,
134→    prev_regs: [u32; 8],
135→    prev_pc: u32,
136→    labels: HashMap<String, u32>,
137→    reverse_labels: HashMap<u32, String>,
138→    program_end: u32,
139→    /// Address of vm_state struct in emulator memory.
140→    vm_state_addr: u32,
141→    /// Address of eval_stack base.
142→    eval_stack_base: u32,
143→    /// Address of call_stack base.
144→    call_stack_base: u32,
145→    /// Address of code_seg.
146→    code_seg_addr: u32,
147→    /// Address of vm_loop (top of fetch-decode-execute cycle).
148→    vm_loop_addr: u32,
149→    /// Previous p-code PC for change detection.
150→    prev_pcode_pc: u32,
151→    /// Show COR24 host drill-down panel.
152→    show_host: bool,
153→}
154→
155→impl Debugger {
156→    fn load_binary(&mut self) {
157→        let mut asm = Assembler::new();
158→        let result = asm.assemble(self.config.assembly());
159→
160→        if !result.errors.is_empty() {
161→            self.output = "Assembly errors:\n".to_string();
162→            for e in &result.errors {
163→                self.output.push_str(e);
164→                self.output.push('\n');
165→            }
166→            return;
167→        }
168→
169→        self.labels = result.labels.clone();
170→        self.reverse_labels = result
171→            .labels
172→            .iter()
173→            .map(|(name, &addr)| (addr, name.clone()))
174→            .collect();
175→        self.program_end = result.bytes.len() as u32;
176→
177→        // Resolve key VM addresses from labels.
178→        self.vm_state_addr = result.labels.get("vm_state").copied().unwrap_or(0);
179→        self.eval_stack_base = result.labels.get("eval_stack").copied().unwrap_or(0);
180→        self.call_stack_base = result.labels.get("call_stack").copied().unwrap_or(0);
181→        self.code_seg_addr = result.labels.get("code_seg").copied().unwrap_or(0);
182→        self.vm_loop_addr = result.labels.get("vm_loop").copied().unwrap_or(0);
183→
184→        self.emulator.hard_reset();
185→        self.emulator.set_uart_tx_busy_cycles(0);
186→        self.emulator.load_program(0, &result.bytes);
187→        self.emulator.load_program_extent(result.bytes.len() as u32);
188→        self.emulator.set_pc(0);
189→        self.output.clear();
190→        self.halted = false;
191→        self.prev_regs = [0; 8];
192→        self.prev_pc = 0;
193→        self.prev_pcode_pc = 0;
194→
195→        // Start paused — debugger mode.
196→        self.running = false;
197→        self.emulator.pause();
198→    }
199→
200→    fn schedule_tick(&mut self, ctx: &Context<Self>) {
201→        let link = ctx.link().clone();
202→        self._tick_handle = Some(Timeout::new(TICK_MS, move || {
203→            link.send_message(Msg::Tick);
204→        }));
205→    }
206→
207→    /// Read the p-code VM state struct from emulator memory.
208→    fn read_pcode_state(&self) -> PcodeState {
209→        let base = self.vm_state_addr;
210→        PcodeState {
211→            pc: self.emulator.read_word(base + vm_offsets::PC),
212→            esp: self.emulator.read_word(base + vm_offsets::ESP),
213→            csp: self.emulator.read_word(base + vm_offsets::CSP),
214→            fp_vm: self.emulator.read_word(base + vm_offsets::FP_VM),
215→            gp: self.emulator.read_word(base + vm_offsets::GP),
216→            hp: self.emulator.read_word(base + vm_offsets::HP),
217→            code_base: self.emulator.read_word(base + vm_offsets::CODE),
218→            status: self.emulator.read_word(base + vm_offsets::STATUS),
219→            trap_code: self.emulator.read_word(base + vm_offsets::TRAP_CODE),
220→        }
221→    }
222→
223→    /// Decode a p-code instruction at the given offset within code_seg.
224→    fn decode_pcode_at(&self, code_base: u32, offset: u32) -> PcodeInstr {
225→        let addr = code_base + offset;
226→        let opcode = self.emulator.read_byte(addr);
227→        let (name, operand, size) = Self::decode_pcode_opcode(opcode, addr, &self.emulator);
228→        PcodeInstr {
229→            addr: offset,
230→            name,
231→            operand,
232→            size,
233→        }
234→    }
235→
236→    fn decode_pcode_opcode(
237→        opcode: u8,
238→        addr: u32,
239→        emu: &EmulatorCore,
240→    ) -> (&'static str, Option<u32>, u32) {
241→        let name = PCODE_NAMES
242→            .iter()
243→            .find(|(op, _)| *op == opcode)
244→            .map(|(_, n)| *n)
245→            .unwrap_or("???");
246→
247→        match opcode {
248→            // 3-byte operand instructions (push, jmp, jz, jnz, call, calln)
249→            0x01 | 0x30 | 0x31 | 0x32 | 0x33 | 0x35 => {
250→                let operand = emu.read_word(addr + 1) & 0xFFFFFF;
251→                (name, Some(operand), 4)
252→            }
253→            // 1-byte operand instructions (push_s, trap, enter, loadl, storel, loadg, storeg,
254→            // addrl, addrg, loada, storea, loadn, storen, sys)
255→            0x02 | 0x36 | 0x40..=0x4B | 0x60 => {
256→                let operand = emu.read_byte(addr + 1) as u32;
257→                (name, Some(operand), 2)
258→            }
259→            // No operand
260→            _ => (name, None, 1),
261→        }
262→    }
263→
264→    /// Disassemble p-code instructions around the current p-code PC.
265→    fn disassemble_pcode(&self, pstate: &PcodeState, count: usize) -> Vec<PcodeInstr> {
266→        let mut instrs = Vec::new();
267→        let mut offset = 0u32;
268→        let code_limit = self.eval_stack_base.saturating_sub(pstate.code_base);
269→
270→        // Scan from start of code segment to build instruction list.
271→        // This handles variable-length instructions correctly.
272→        while offset < code_limit && instrs.len() < 256 {
273→            let instr = self.decode_pcode_at(pstate.code_base, offset);
274→            offset += instr.size;
275→            instrs.push(instr);
276→        }
277→
278→        // Find index of current PC instruction.
279→        let current_idx = instrs.iter().position(|i| i.addr == pstate.pc).unwrap_or(0);
280→
281→        // Window around current PC.
282→        let start = current_idx.saturating_sub(4);
283→        let end = (current_idx + count).min(instrs.len());
284→        instrs.into_iter().skip(start).take(end - start).collect()
285→    }
286→
287→    /// Read eval stack entries (each 3 bytes / 1 word).
288→    fn read_eval_stack(&self, pstate: &PcodeState) -> Vec<u32> {
289→        let mut stack = Vec::new();
290→        let mut addr = self.eval_stack_base;
291→        while addr < pstate.esp {
292→            stack.push(self.emulator.read_word(addr));
293→            addr += 3;
294→        }
295→        stack
296→    }
297→
298→    /// Disassemble COR24 instructions around current host PC.
299→    fn disassemble_host(&self) -> Vec<(u32, String, bool)> {
300→        let pc = self.emulator.snapshot().pc;
301→        let forward = self.emulator.disassemble(pc, DISASM_AFTER + 1);
302→
303→        let mut before = Vec::new();
304→        if DISASM_BEFORE > 0 && pc > 0 {
305→            let scan_start = pc.saturating_sub((DISASM_BEFORE as u32) * 4 + 8);
306→            let all = self.emulator.disassemble(scan_start, 128);
307→            for &(addr, ref mnemonic, _size) in &all {
308→                if addr < pc {
309→                    before.push((addr, mnemonic.clone()));
310→                } else {
311→                    break;
312→                }
313→            }
314→            let skip = before.len().saturating_sub(DISASM_BEFORE);
315→            before = before.into_iter().skip(skip).collect();
316→        }
317→
318→        let mut result: Vec<(u32, String, bool)> = Vec::new();
319→        for (addr, mnemonic) in before {
320→            result.push((addr, mnemonic, false));
321→        }
322→        for (addr, mnemonic, _size) in forward {
323→            result.push((addr, mnemonic, addr == pc));
324→        }
325→        result
326→    }
327→
328→    fn collect_uart(&mut self) {
329→        let uart = self.emulator.get_uart_output();
330→        if !uart.is_empty() {
331→            self.output.push_str(uart);
332→            self.emulator.clear_uart_output();
333→        }
334→    }
335→
336→    fn save_prev_state(&mut self) {
337→        let snap = self.emulator.snapshot();
338→        self.prev_regs = snap.regs;
339→        self.prev_pc = snap.pc;
340→        self.prev_pcode_pc = self.read_pcode_state().pc;
341→    }
342→
343→    fn check_halted(&mut self, reason: StopReason) {
344→        if matches!(reason, StopReason::Halted) {
345→            self.halted = true;
346→            self.running = false;
347→        }
348→    }
349→}
350→
351→impl Component for Debugger {
352→    type Message = Msg;
353→    type Properties = ();
354→
355→    fn create(ctx: &Context<Self>) -> Self {
356→        ctx.link().send_message(Msg::Init);
357→        let mut emulator = EmulatorCore::new();
358→        emulator.set_uart_tx_busy_cycles(0);
359→        Self {
360→            emulator,
361→            config: VmConfig::default(),
362→            output: String::new(),
363→            running: false,
364→            halted: false,
365→            _tick_handle: None,
366→            prev_regs: [0; 8],
367→            prev_pc: 0,
368→            labels: HashMap::new(),
369→            reverse_labels: HashMap::new(),
370→            program_end: 0,
371→            vm_state_addr: 0,
372→            eval_stack_base: 0,
373→            call_stack_base: 0,
374→            code_seg_addr: 0,
375→            vm_loop_addr: 0,
376→            prev_pcode_pc: 0,
377→            show_host: false,
378→        }
379→    }
380→
381→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
382→        match msg {
383→            Msg::Init => {
384→                self.load_binary();
385→                true
386→            }
387→            Msg::Tick => {
388→                if !self.running || self.halted {
389→                    return false;
390→                }
391→
392→                self.save_prev_state();
393→                let result = self.emulator.run_batch(BATCH_SIZE);
394→                self.collect_uart();
395→                self.check_halted(result.reason);
396→
397→                if self.running && !self.halted {
398→                    self.schedule_tick(ctx);
399→                }
400→                true
401→            }
402→            Msg::Reset => {
403→                self.running = false;
404→                self._tick_handle = None;
405→                self.load_binary();
406→                true
407→            }
408→            Msg::StepPcode => {
409→                if self.halted {
410→                    return false;
411→                }
412→                self.save_prev_state();
413→                let pstate = self.read_pcode_state();
414→
415→                if pstate.code_base == 0 {
416→                    // VM not yet initialized — run COR24 init until host PC
417→                    // reaches vm_loop (the top of the fetch-decode cycle).
418→                    for _ in 0..100_000 {
419→                        let result = self.emulator.step();
420→                        self.collect_uart();
421→                        if matches!(result.reason, StopReason::Halted) {
422→                            self.halted = true;
423→                            self.running = false;
424→                            break;
425→                        }
426→                        if self.vm_loop_addr != 0
427→                            && self.emulator.snapshot().pc == self.vm_loop_addr
428→                        {
429→                            break;
430→                        }
431→                    }
432→                } else {
433→                    // Run COR24 until host PC returns to vm_loop with a
434→                    // different p-code PC, meaning one full p-code instruction
435→                    // has completed its fetch-decode-execute cycle.
436→                    // Run one full p-code fetch-decode-execute cycle:
437→                    // step COR24 instructions until host PC returns to
438→                    // vm_loop. Use do-while pattern (check after first step)
439→                    // because we may already be sitting on vm_loop.
440→                    let mut i = 0u32;
441→                    loop {
442→                        let result = self.emulator.step();
443→                        self.collect_uart();
444→                        i += 1;
445→                        if matches!(result.reason, StopReason::Halted) {
446→                            self.halted = true;
447→                            self.running = false;
448→                            break;
449→                        }
450→                        if self.read_pcode_state().status != 0 {
451→                            break;
452→                        }
453→                        if i > 1 && self.emulator.snapshot().pc == self.vm_loop_addr {
454→                            break;
455→                        }
456→                        if i >= 50_000 {
457→                            break;
458→                        }
459→                    }
460→                }
461→                true
462→            }
463→            Msg::StepHost => {
464→                if self.halted {
465→                    return false;
466→                }
467→                self.save_prev_state();
468→                let result = self.emulator.step();
469→                self.collect_uart();
470→                self.check_halted(result.reason);
471→                true
472→            }
473→            Msg::PauseResume => {
474→                if self.halted {
475→                    return false;
476→                }
477→                self.running = !self.running;
478→                if self.running {
479→                    self.emulator.resume();
480→                    self.schedule_tick(ctx);
481→                } else {
482→                    self.emulator.pause();
483→                    self._tick_handle = None;
484→                }
485→                true
486→            }
487→            Msg::ToggleHost => {
488→                self.show_host = !self.show_host;
489→                true
490→            }
491→        }
492→    }
493→
494→    fn view(&self, ctx: &Context<Self>) -> Html {
495→        let link = ctx.link();
496→        let snap = self.emulator.snapshot();
497→        let pstate = self.read_pcode_state();
498→        let vm_initialized = pstate.code_base != 0;
499→        let pcode_instrs = if vm_initialized {
500→            self.disassemble_pcode(&pstate, 12)
501→        } else {
502→            Vec::new()
503→        };
504→        let eval_stack = if vm_initialized {
505→            self.read_eval_stack(&pstate)
506→        } else {
507→            Vec::new()
508→        };
509→
510→        let vm_status = if !vm_initialized {
511→            "INIT"
512→        } else {
513→            match pstate.status {
514→                0 => "RUNNING",
515→                1 => "HALTED",
516→                2 => "TRAPPED",
517→                _ => "???",
518→            }
519→        };
520→
521→        html! {
522→            <div class="debugger">
523→                // Control bar
524→                <div class="control-bar">
525→                    <button onclick={link.callback(|_| Msg::Reset)}
526→                            class="btn btn-reset">{"Reset"}</button>
527→                    <button onclick={link.callback(|_| Msg::StepPcode)}
528→                            class="btn btn-step"
529→                            disabled={self.halted}>{"Step P-Code"}</button>
530→                    <button onclick={link.callback(|_| Msg::StepHost)}
531→                            class="btn btn-step-host"
532→                            disabled={self.halted}>{"Step Host"}</button>
533→                    <button onclick={link.callback(|_| Msg::PauseResume)}
534→                            class="btn btn-run"
535→                            disabled={self.halted}>
536→                        { if self.running { "Pause" } else { "Run" } }
537→                    </button>
538→                    <button onclick={link.callback(|_| Msg::ToggleHost)}
539→                            class={if self.show_host { "btn btn-toggle active" } else { "btn btn-toggle" }}>
540→                        {"COR24"}
541→                    </button>
542→                    <span class="status">{ vm_status }</span>
543→                    <span class="pc-display">
544→                        { format!("P-Code PC: {:04X}", pstate.pc) }
545→                    </span>
546→                    <span class="pc-display host-pc">
547→                        { format!("Host PC: {:06X}", snap.pc) }
548→                    </span>
549→                </div>
550→
551→                // Main panels area — 3-column layout
552→                <div class="panels">
553→                    // Left: P-code disassembly
554→                    <div class="panel panel-disasm">
555→                        <h3>{"P-Code Disassembly"}</h3>
556→                        { if !vm_initialized {
557→                            html! { <div class="disasm-init">{"Press Step P-Code to initialize VM"}</div> }
558→                        } else {
559→                            html! {}
560→                        }}
561→                        <div class="disasm-view">
562→                            { for pcode_instrs.iter().map(|instr| {
563→                                let is_current = instr.addr == pstate.pc;
564→                                let line_class = if is_current {
565→                                    "disasm-line current"
566→                                } else {
567→                                    "disasm-line"
568→                                };
569→                                let operand_str = match instr.operand {
570→                                    Some(v) => format!(" {:06X}", v),
571→                                    None => String::new(),
572→                                };
573→                                html! {
574→                                    <div class={line_class}>
575→                                        <span class="disasm-marker">
576→                                            { if is_current { "\u{25b6}" } else { " " } }
577→                                        </span>
578→                                        <span class="disasm-addr">
579→                                            { format!("{:04X}", instr.addr) }
580→                                        </span>
581→                                        <span class="disasm-opcode">
582→                                            { instr.name }
583→                                        </span>
584→                                        <span class="disasm-operand">
585→                                            { operand_str }
586→                                        </span>
587→                                    </div>
588→                                }
589→                            })}
590→                        </div>
591→                    </div>
592→
593→                    // Center: VM state + eval stack + output
594→                    <div class="panel-center">
595→                        // VM state
596→                        <div class="panel panel-vm-state">
597→                            <h3>{"VM State"}</h3>
598→                            <table class="state-table">
599→                                <tr class={if pstate.pc != self.prev_pcode_pc { "changed" } else { "" }}>
600→                                    <td class="state-name">{"PC"}</td>
601→                                    <td class="state-val">{ format!("{:04X}", pstate.pc) }</td>
602→                                </tr>
603→                                <tr>
604→                                    <td class="state-name">{"ESP"}</td>
605→                                    <td class="state-val">{ format!("{:06X}", pstate.esp) }</td>
606→                                </tr>
607→                                <tr>
608→                                    <td class="state-name">{"CSP"}</td>
609→                                    <td class="state-val">{ format!("{:06X}", pstate.csp) }</td>
610→                                </tr>
611→                                <tr>
612→                                    <td class="state-name">{"FP"}</td>
613→                                    <td class="state-val">{ format!("{:06X}", pstate.fp_vm) }</td>
614→                                </tr>
615→                                <tr>
616→                                    <td class="state-name">{"GP"}</td>
617→                                    <td class="state-val">{ format!("{:06X}", pstate.gp) }</td>
618→                                </tr>
619→                                <tr>
620→                                    <td class="state-name">{"HP"}</td>
621→                                    <td class="state-val">{ format!("{:06X}", pstate.hp) }</td>
622→                                </tr>
623→                                { if pstate.status == 2 {
624→                                    html! {
625→                                        <tr class="trap">
626→                                            <td class="state-name">{"TRAP"}</td>
627→                                            <td class="state-val">{ format!("{}", pstate.trap_code) }</td>
628→                                        </tr>
629→                                    }
