/// Read call frames by walking from call_stack_base to CSP.
/// Each frame header is 12 bytes: return_pc(3), dynamic_link(3), static_link(3), saved_esp(3).
fn read_call_frames(&self, pstate: &PcodeState) -> Vec<CallFrame> {
    let mut frames = Vec::new();
    let mut addr = self.call_stack_base;
    while addr + 12 <= pstate.csp {
        frames.push(CallFrame {
            base_addr: addr,
            return_pc: self.emulator.read_word(addr),
            dynamic_link: self.emulator.read_word(addr + 3),
            static_link: self.emulator.read_word(addr + 6),
            saved_esp: self.emulator.read_word(addr + 9),
        });
        // Skip to next frame: header(12) + locals between this frame and next
        // We find the next frame by looking for the next 12-byte boundary
        // or by scanning forward. For now, advance by 12 and skip locals.
        // Actually, frames may have locals between them. Walk using dynamic_link
        // chain from current fp_vm instead.
        addr += 12;
        // Skip any local slots — locals are between frame header end and next frame header.
        // We can detect by checking if addr < csp and the next 12 bytes look like a frame,
        // but simpler: just advance by 3 (one word) until we find a plausible frame or hit csp.
        // For correctness, use fp_vm chain instead.
        break;
    }

    // Walk frame chain from current fp_vm backwards via dynamic_link.
    // fp_vm points to first local; frame header is at fp_vm - 12.
    let mut fp = pstate.fp_vm;
    frames.clear();
    while fp >= self.call_stack_base + 12 {
        let header = fp - 12;
        if header < self.call_stack_base {
            break;
        }
        frames.push(CallFrame {
            base_addr: header,
            return_pc: self.emulator.read_word(header),
            dynamic_link: self.emulator.read_word(header + 3),
            static_link: self.emulator.read_word(header + 6),
            saved_esp: self.emulator.read_word(header + 9),
        });
        let prev_fp = self.emulator.read_word(header + 3);
        if prev_fp == 0 || prev_fp >= fp {
            break; // End of chain or invalid link.
        }
        fp = prev_fp;
    }
    frames.reverse(); // Oldest frame first.
    frames
}

/// Compute memory regions for the visualization bar.
fn memory_regions(&self, pstate: &PcodeState) -> Vec<MemRegion> {
    if pstate.code_base == 0 {
        return Vec::new();
    }
    let code_size = self.eval_stack_base.saturating_sub(pstate.code_base);
    let eval_used = pstate.esp.saturating_sub(self.eval_stack_base);
    let eval_cap = self.call_stack_base.saturating_sub(self.eval_stack_base);
    let call_used = pstate.csp.saturating_sub(self.call_stack_base);
    // Globals and heap are after call stack in the memory map.
    let globals_size = if pstate.gp > 0 { 24 } else { 0 }; // 8 words = 24 bytes
    let heap_used = if pstate.hp > pstate.gp { pstate.hp - pstate.gp } else { 0 };

    vec![
        MemRegion { name: "Code", css_class: "region-code", start: pstate.code_base, size: code_size },
        MemRegion { name: "EStack", css_class: "region-estack", start: self.eval_stack_base, size: eval_used.max(eval_cap) },
        MemRegion { name: "CStack", css_class: "region-cstack", start: self.call_stack_base, size: call_used.max(1) },
        MemRegion { name: "Globals", css_class: "region-globals", start: pstate.gp, size: globals_size },
        MemRegion { name: "Heap", css_class: "region-heap", start: pstate.hp.saturating_sub(heap_used), size: heap_used.max(1) },
    ]
}

