                                                    html! {}
                                                }}
                                                <div class={line_class}>
                                                    <span class="disasm-marker">
                                                        { if *is_current { "\u{25b6}" } else { " " } }
                                                    </span>
                                                    <span class="disasm-addr">
                                                        { format!("{:06X}", addr) }
                                                    </span>
                                                    <span class="disasm-instr">
                                                        { mnemonic }
                                                    </span>
                                                </div>
                                            </>
                                        }
                                    })}
                                </div>
                            </div>
                        }
                    } else {
                        html! {}
                    }}
                </div>
            </div>
        }
    }
}

